    /// <summary>
    /// Insert InventJournal data(Table and Trans)
    /// </summary>
    /// <param name = "_receiptAndPaymentResultIfTableRecord">KJP_SM_ReceiptAndPaymentResultIfTable</param>
    /// <param name = "_inventJournalNameId">inventJournalNameId</param>
    /// <param name = "_inventJournalNameRecord">inventJournalNameRecord</param>
    /// <param name = "_isCreatInventJournalTable">_isCreatInventJournalTable</param>
    /// <param name = "_inventJournalId">_inventJournalId</param>
    /// <param name = "_prodId">ProdId</param>
    /// <returns>ProdJournalId</returns>
    public static InventJournalId insertInventJournal(
        KJP_SM_ReceiptAndPaymentResultIfTable _receiptAndPaymentResultIfTableRecord,
        JournalNameId _inventJournalNameId,
        InventJournalName _inventJournalNameRecord,
        boolean _isCreatInventJournalTable,
        InventJournalId _inventJournalId,
        ProdId _prodId)
    {
        InventJournalTable insertInventJournalTableRecord;
        InventJournalTrans insertInventJournalTransRecord;
        InventDim inventDimNew;
        voucher voucherNum;

        InventLocation inventLocationRecord  = InventLocation::find(_receiptAndPaymentResultIfTableRecord.DeliveryLocationCD);

        ttsbegin;

        if(_isCreatInventJournalTable)
        {
            // insert InventJournalTable data
            insertInventJournalTableRecord.clear();
            insertInventJournalTableRecord.initValue();
            insertInventJournalTableRecord.JournalId = JournalTableData::newTable(insertInventJournalTableRecord).nextJournalId();
            insertInventJournalTableRecord.JournalType = InventJournalType::Movement;
            insertInventJournalTableRecord.InventSiteId = inventLocationRecord.InventSiteId;
            insertInventJournalTableRecord.Description = _inventJournalNameRecord.Description;
            insertInventJournalTableRecord.VoucherNumberSequenceTable  = _inventJournalNameRecord.VoucherNumberSequenceTable;
            insertInventJournalTableRecord.VoucherDraw = _inventJournalNameRecord.VoucherDraw;
            insertInventJournalTableRecord.VoucherChange = _inventJournalNameRecord.VoucherChange;
            insertInventJournalTableRecord.DetailSummary = _inventJournalNameRecord.DetailSummary;
            insertInventJournalTableRecord.DeletePostedLines = _inventJournalNameRecord.DeletePostedLines;
            insertInventJournalTableRecord.LedgerDimension = _inventJournalNameRecord.LedgerDimension;
            insertInventJournalTableRecord.Reservation = _inventJournalNameRecord.Reservation;
            insertInventJournalTableRecord.InventLocationId = _receiptAndPaymentResultIfTableRecord.DeliveryLocationCD;
            insertInventJournalTableRecord.JournalNameId = _inventJournalNameId;
            insertInventJournalTableRecord.NumOfLines = KJP_CM_ConstantHelper::numberOne;
            insertInventJournalTableRecord.KJPSMRemarks = _prodId;
            insertInventJournalTableRecord.insert();
        }
        else
        {
            insertInventJournalTableRecord = InventJournalTable::find(_inventJournalId);
        }

        // insert InventJournalTrans data
        insertInventJournalTransRecord.clear();
        insertInventJournalTransRecord.initValue();
        insertInventJournalTransRecord.initFromInventJournalTable(insertInventJournalTableRecord);
        insertInventJournalTransRecord.JournalId = insertInventJournalTableRecord.JournalId;
        insertInventJournalTransRecord.ItemId = _receiptAndPaymentResultIfTableRecord.ItemCD;
        //if(_isCreatInventJournalTable)
        //{
        //    insertInventJournalTransRecord.LineNum = KJP_CM_ConstantHelper::numberOne;
        //}
        //else
        //{
        //    insertInventJournalTransRecord.LineNum = _lineNum;
        //}
        if (_receiptAndPaymentResultIfTableRecord.UpdateCategory == updateCategory_1)
        {
            insertInventJournalTransRecord.Qty = _receiptAndPaymentResultIfTableRecord.Quantity * -1;
        }
        else if (_receiptAndPaymentResultIfTableRecord.UpdateCategory == updateCategory_3)
        {
            insertInventJournalTransRecord.Qty = _receiptAndPaymentResultIfTableRecord.Quantity;
        }
        else if (_receiptAndPaymentResultIfTableRecord.UpdateCategory == updateCategory_2)
        {
            insertInventJournalTransRecord.Qty = KJP_SM_InputResultCommonClass::getSumInventJournalQtyByProdId(_prodId, _receiptAndPaymentResultIfTableRecord.ItemCD, _receiptAndPaymentResultIfTableRecord.LotNo) * -1;
        }

        insertInventJournalTransRecord.TransDate =
            str2Date(subStr(_receiptAndPaymentResultIfTableRecord.ActualDateAndTimeStr,1,8), 321);
        insertInventJournalTransRecord.LedgerDimension = _inventJournalNameRecord.LedgerDimension;
        insertInventJournalTransRecord.PriceUnit = KJP_CM_ConstantHelper::numberOne;
        insertInventJournalTransRecord.Unit = _receiptAndPaymentResultIfTableRecord.UnitCD;
        insertInventJournalTransRecord.UnitQty = KJP_CM_ConstantHelper::numberOne;
        inventDimNew.InventSiteId = InventLocation::find(_receiptAndPaymentResultIfTableRecord.DeliveryLocationCD).InventSiteId;
        inventDimNew.InventLocationId = _receiptAndPaymentResultIfTableRecord.DeliveryLocationCD;
        inventDimNew.inventBatchId = _receiptAndPaymentResultIfTableRecord.LotNo;
        insertInventJournalTransRecord.InventDimId = InventDim::findOrCreate(inventDimNew).inventDimId;
        voucherNum = new JournalVoucherNum(JournalTableData::newTable(InventJournalTable::find(insertInventJournalTableRecord.JournalId))).getNew(false);
        insertInventJournalTransRecord.Voucher = voucherNum;

        if (_receiptAndPaymentResultIfTableRecord.BurdenDepartmentCD)
        {
            insertInventJournalTransRecord.DefaultDimension = KJP_CM_Utils::updateDefaultDimension(
                InventTable::find(_receiptAndPaymentResultIfTableRecord.ItemCD).DefaultDimension
                , [KJP_CM_ConstantHelper::jpDepartMent]
                , [_receiptAndPaymentResultIfTableRecord.BurdenDepartmentCD]);
        }
        else
        {
            insertInventJournalTransRecord.DefaultDimension = KJP_CM_Utils::updateDefaultDimension(
                InventTable::find(_receiptAndPaymentResultIfTableRecord.ItemCD).DefaultDimension
                , [KJP_CM_ConstantHelper::jpDepartMent]
                , [InventLocation::find(_receiptAndPaymentResultIfTableRecord.DeliveryLocationCD).KJPFIJP_DepartmentStr]);
        }
        insertInventJournalTransRecord.insert();

        ttscommit;

        return insertInventJournalTableRecord.JournalId;
    }

    /// <summary>Gets the sum quantity of Prod Id.</summary>
    /// <param name = "_prodId">ProdId</param>
    /// <param name = "_itemId">ItemId</param>
    /// <param name = "_lotNo">KJP_SM_LotNo</param>
    /// <returns>The sum quantity</returns>
    public static InventQtyJournal getSumInventJournalQtyByProdId(ProdId _prodId, ItemId _itemId, KJP_SM_LotNo _lotNo)
    {
        InventJournalTable inventJournalTable;
        InventJournalTrans inventJournalTrans;
        InventDim inventDim;

        select sum(Qty)
        from inventJournalTrans
            join inventDim
        where inventDim.inventDimId == inventJournalTrans.InventDimId
            && inventDim.inventBatchId == _lotNo
            join JournalId from inventJournalTable
        where inventJournalTrans.JournalId == inventJournalTable.JournalId
            && inventJournalTrans.ItemId == _itemId
            && inventJournalTable.Posted == NoYes::Yes
            && inventJournalTable.KJPSMRemarks == _prodId;

        return inventJournalTrans.Qty;
    }
